import os
import cv2

# Specify the path to your image
image_path = r'E:\ABB\AI\yolov9\data\data_realsense\color_image_20241014-112403.jpg'

# Read the image to get its dimensions
image = cv2.imread(image_path)
image_height, image_width, _ = image.shape

# Specify the path to your detection result (generated by YOLOv9)
detections_path = r'E:\ABB\AI\yolov9\runs\detect\exp26\color_image_20241014-112403.txt'

# Ensure the detection results file exists
if not os.path.exists(detections_path):
    raise FileNotFoundError(f"Detection results file not found: {detections_path}")

bboxes = []
class_ids = []
conf_scores = []

# Read and parse the detection results
with open(detections_path, 'r') as file:
    for line in file:
        components = line.split()
        if len(components) < 6:
            continue  # Ensure each line has enough components
        class_id = int(components[0])  # Class ID
        confidence = float(components[5])  # Confidence score
        cx, cy, w, h = [float(x) for x in components[1:5]]  # Center x, y, width, height (normalized)

        # Convert from normalized [0, 1] to image scale
        cx *= image_width
        cy *= image_height
        w *= image_width
        h *= image_height

        # Convert the center x, y, width, and height to xmin, ymin, xmax, ymax
        xmin = cx - w / 2
        ymin = cy - h / 2
        xmax = cx + w / 2
        ymax = cy + h / 2

        class_ids.append(class_id)
        bboxes.append((xmin, ymin, xmax, ymax))
        conf_scores.append(confidence)

# Display the results
for class_id, bbox, conf in zip(class_ids, bboxes, conf_scores):
    print(f'Class ID: {class_id}, Confidence: {conf:.2f}, BBox coordinates: {bbox}')
